import React, { useEffect, useState } from "react";
import axios from "axios";
import logout from "../utils/logout";
import "./mentorDashboard.css";

export default function MentorDashboard() {
  const mentorId = localStorage.getItem("userId");
  const [requests, setRequests] = useState([]);
  const [activeTab, setActiveTab] = useState("requests");

  const loadRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5050/api/mentor-requests/mentor/${mentorId}`
      );
      setRequests(res.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await axios.put(`http://localhost:5050/api/mentor-requests/${id}`, { status });
      alert(`Request ${status}`);
      loadRequests();
    } catch (err) {
      alert("Failed to update status");
    }
  };

  useEffect(() => {
    loadRequests();
  }, []);

  return (
    <div className="mentor-dashboard">
      <div className="header">
        <h2>Mentor Dashboard</h2>
        <button onClick={() => logout()}>Logout</button>
      </div>

      <div className="tabs">
        {["requests"].map((tab) => (
          <button
            key={tab}
            className={activeTab === tab ? "active" : ""}
            onClick={() => setActiveTab(tab)}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      {activeTab === "requests" && (
        <div className="requests-list">
          <h3>Project Requests</h3>
          {requests.length === 0 ? (
            <p>No requests yet.</p>
          ) : (
            requests.map((r) => (
              <div key={r.id} className="card">
                <h4>{r.project_title}</h4>
                <p><b>Student:</b> {r.student_name}</p>
                <p><b>Domain:</b> {r.domain}</p>
                <p><b>Status:</b> {r.status}</p>
                {r.status === "pending" && (
                  <>
                    <button onClick={() => updateStatus(r.id, "accepted")}>Accept</button>
                    <button onClick={() => updateStatus(r.id, "rejected")}>Reject</button>
                  </>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
